import type { CareerQuestion } from "./pharmacy-tech-questions-extended";

export const pharmacyTechQuestionsPEBC: (CareerQuestion & { certification?: string })[] = [
  {"id":"pebc-001","stem":"In Canada, which regulatory body is responsible for scheduling drugs into different categories?","options":["Health Canada","NAPRA (National Association of Pharmacy Regulatory Authorities)","Canadian Pharmacists Association","Provincial Colleges of Pharmacy"],"correctIndex":1,"rationale":"NAPRA establishes the National Drug Schedules (I, II, III, Unscheduled) that determine how drugs are sold in Canada. Health Canada approves drugs for market; provincial colleges regulate pharmacy practice.","difficulty":1,"category":"Regulations/Law","topic":"Canadian drug scheduling","certification":"PEBC"},
  {"id":"pebc-002","stem":"Under the NAPRA drug scheduling system, Schedule I drugs in Canada require:","options":["No professional intervention","A prescription from an authorized prescriber","Sale behind the counter with pharmacist advice","Over-the-counter availability in any retail store"],"correctIndex":1,"rationale":"NAPRA Schedule I drugs require a prescription. Schedule II drugs are behind-the-counter (pharmacist-only). Schedule III are available in the self-selection area of a pharmacy. Unscheduled drugs can be sold anywhere.","difficulty":1,"category":"Regulations/Law","topic":"NAPRA schedules","certification":"PEBC"},
  {"id":"pebc-003","stem":"What is the Canadian equivalent of the US NDC number for identifying drug products?","options":["DIN (Drug Identification Number)","NPN (Natural Product Number)","GTIN (Global Trade Item Number)","CAS (Chemical Abstracts Service) Number"],"correctIndex":0,"rationale":"The DIN (Drug Identification Number) is an 8-digit number assigned by Health Canada that uniquely identifies each drug product sold in Canada, including the manufacturer, product name, active ingredient, strength, dosage form, and route of administration.","difficulty":1,"category":"Prescription Processing","topic":"DIN numbers","certification":"PEBC"},
  {"id":"pebc-004","stem":"In Canada, which of the following is a Schedule II (behind-the-counter) drug that does not require a prescription?","options":["Oxycodone","Insulin","Codeine products with ≤8 mg per tablet in some provinces","Morphine"],"correctIndex":2,"rationale":"In some Canadian provinces, low-dose codeine products (≤8 mg codeine per tablet, combined with at least two other active ingredients) can be sold behind the counter by a pharmacist without a prescription. This is unique to Canada and not the case in the US.","difficulty":2,"category":"Regulations/Law","topic":"behind-the-counter drugs","certification":"PEBC"},
  {"id":"pebc-005","stem":"A prescription in Canada reads: 'Amoxicillin 500 mg PO TID × 7 days.' The patient asks about the cost. What provincial program may cover this?","options":["Medicare Part D","Ontario Drug Benefit (ODB) or equivalent provincial drug plan","Medicaid","TRICARE"],"correctIndex":1,"rationale":"Canadian provinces have their own drug benefit programs (ODB in Ontario, PharmaCare in BC, RAMQ in Quebec, etc.) that cover eligible residents. Medicare Part D, Medicaid, and TRICARE are US programs not applicable in Canada.","difficulty":1,"category":"Prescription Processing","topic":"Canadian drug coverage","certification":"PEBC"},
  {"id":"pebc-006","stem":"Which controlled substance scheduling system is used in Canada?","options":["DEA Schedules I-V","CDSA (Controlled Drugs and Substances Act) Schedules I-VI","NAPRA Schedules I-III","Provincial Drug Schedules only"],"correctIndex":1,"rationale":"Canada uses the Controlled Drugs and Substances Act (CDSA) with Schedules I-VI for narcotics and controlled substances. This is distinct from the US DEA scheduling system. The CDSA regulates substances like opioids, stimulants, and cannabis.","difficulty":2,"category":"Regulations/Law","topic":"CDSA schedules","certification":"PEBC"},
  {"id":"pebc-007","stem":"What is the generic name for Apo-Atorvastatin, a commonly dispensed Canadian generic product?","options":["Simvastatin","Rosuvastatin","Atorvastatin","Pravastatin"],"correctIndex":2,"rationale":"Apo-Atorvastatin is a Canadian generic brand manufactured by Apotex containing atorvastatin. Canadian generic manufacturers include Apotex (Apo-), Teva, and Pharmascience (pms-). The active ingredient atorvastatin is a statin for cholesterol reduction.","difficulty":1,"category":"Pharmacology","topic":"Canadian generics","certification":"PEBC"},
  {"id":"pebc-008","stem":"A prescription calls for 240 mL of amoxicillin 250 mg/5 mL. Using the metric system standard in Canadian pharmacy, how many total grams of amoxicillin are in the bottle?","options":["6 g","12 g","24 g","48 g"],"correctIndex":1,"rationale":"250 mg/5 mL × 240 mL = 12,000 mg = 12 g. Canada uses the metric system exclusively. Converting between mg and g (÷1000) is a fundamental skill for Canadian pharmacy technicians.","difficulty":2,"category":"Dosage Calculations","topic":"metric calculations","certification":"PEBC"},
  {"id":"pebc-009","stem":"In Canadian pharmacy practice, what does the abbreviation 'Rx' signify on a prescription?","options":["Recommended dose","Recipe/take thou (a prescription)","Refill authorized","Return for reassessment"],"correctIndex":1,"rationale":"'Rx' derives from the Latin word 'recipe' meaning 'take thou.' It indicates a prescription medication. In Canadian practice, Rx distinguishes Schedule I (prescription-only) drugs from Schedule II and III (non-prescription) products.","difficulty":1,"category":"Prescription Processing","topic":"prescription terminology","certification":"PEBC"},
  {"id":"pebc-010","stem":"Which Canadian regulatory body approves new drug submissions and issues Drug Identification Numbers?","options":["NAPRA","Provincial Colleges of Pharmacy","Health Canada","Canadian Pharmacists Association"],"correctIndex":2,"rationale":"Health Canada's Therapeutic Products Directorate reviews new drug submissions and issues DINs. NAPRA sets drug schedules. Provincial colleges regulate pharmacy practice within each province. CPhA is a professional advocacy organization.","difficulty":1,"category":"Regulations/Law","topic":"Health Canada","certification":"PEBC"},
  {"id":"pebc-011","stem":"A Canadian patient weighs 88 kg. The prescribed dose is vancomycin 15 mg/kg q12h. What is the dose per administration?","options":["880 mg","1100 mg","1320 mg","1760 mg"],"correctIndex":2,"rationale":"Dose = 15 mg/kg × 88 kg = 1320 mg per dose. In Canada, doses are always calculated using metric units (kg, mg). Vancomycin requires therapeutic drug monitoring with AUC-guided dosing.","difficulty":2,"category":"Dosage Calculations","topic":"weight-based dosing","certification":"PEBC"},
  {"id":"pebc-012","stem":"Under the CDSA, narcotics in Canada (e.g., morphine, oxycodone) require which of the following for prescriptions?","options":["Verbal orders only are acceptable","Written or electronic prescriptions with specific identifying elements","No special requirements beyond a regular prescription","Only nurse practitioners can prescribe narcotics"],"correctIndex":1,"rationale":"CDSA narcotics require written or electronic prescriptions containing the prescriber's name, address, date, patient name and address, drug name, quantity, dosage, and directions. Verbal narcotic prescriptions are permitted only in emergencies in some provinces.","difficulty":2,"category":"Regulations/Law","topic":"narcotic prescriptions","certification":"PEBC"},
  {"id":"pebc-013","stem":"Which of the following is a Canadian-specific vaccination that pharmacy technicians should be familiar with?","options":["MMRV (Priorix-Tetra, available in Canada)","Smallpox vaccine","Yellow fever vaccine","Japanese encephalitis vaccine"],"correctIndex":0,"rationale":"MMRV vaccine (Priorix-Tetra) combines measles, mumps, rubella, and varicella in a single injection. It is part of the Canadian publicly funded immunization schedule. Pharmacy technicians must store vaccines at proper temperatures (2-8°C) per provincial protocols.","difficulty":2,"category":"Pharmacology","topic":"Canadian immunizations","certification":"PEBC"},
  {"id":"pebc-014","stem":"What does 'ODB' stand for in Ontario pharmacy practice?","options":["Ontario Drug Bureau","Ontario Drug Benefit","Outpatient Dispensing Board","Ontario Dispensing Bylaw"],"correctIndex":1,"rationale":"The Ontario Drug Benefit (ODB) program provides coverage for eligible residents including seniors (65+), social assistance recipients, and those in long-term care. Each Canadian province has its own drug benefit program.","difficulty":1,"category":"Prescription Processing","topic":"provincial drug plans","certification":"PEBC"},
  {"id":"pebc-015","stem":"A compounding prescription in Canada requires 30 g of a 1% hydrocortisone cream. How many milligrams of hydrocortisone are needed?","options":["3 mg","30 mg","300 mg","3000 mg"],"correctIndex":2,"rationale":"1% means 1 g per 100 g. For 30 g: (1/100) × 30 = 0.3 g = 300 mg of hydrocortisone. Canadian pharmacy practice uses metric calculations exclusively.","difficulty":2,"category":"Dosage Calculations","topic":"compounding calculations","certification":"PEBC"},
  {"id":"pebc-016","stem":"In Canadian pharmacy, what is a 'DUR' (Drug Utilization Review)?","options":["A procedure to return expired drugs","A review of a patient's medication profile for interactions and duplications","A drug recall notification system","An inventory counting method"],"correctIndex":1,"rationale":"DUR in Canadian pharmacy involves reviewing a patient's medication profile to identify drug-drug interactions, therapeutic duplications, inappropriate dosing, and contraindications before dispensing. It is a pharmacist responsibility, but technicians support the process by maintaining accurate profiles.","difficulty":1,"category":"Prescription Processing","topic":"drug utilization review","certification":"PEBC"},
  {"id":"pebc-017","stem":"The brand name Tylenol No. 1 in Canada contains codeine 8 mg, caffeine, and acetaminophen. Under which schedule does it typically fall?","options":["NAPRA Schedule I (prescription only)","NAPRA Schedule II (behind-the-counter, pharmacist-only)","NAPRA Schedule III (pharmacy self-selection)","Unscheduled (available in any store)"],"correctIndex":1,"rationale":"In most Canadian provinces, Tylenol No. 1 (codeine 8 mg combinations) is NAPRA Schedule II, meaning it is available without a prescription but must be kept behind the pharmacy counter and requires pharmacist intervention before sale.","difficulty":2,"category":"Regulations/Law","topic":"OTC codeine Canada","certification":"PEBC"},
  {"id":"pebc-018","stem":"What is the generic name for ratio-Metformin, a commonly dispensed Canadian generic product?","options":["Glyburide","Metformin","Sitagliptin","Pioglitazone"],"correctIndex":1,"rationale":"ratio-Metformin is a Canadian generic manufactured by Teva (formerly ratiopharm). The 'ratio-' prefix identifies Teva generics in Canada. Metformin is first-line for type 2 diabetes. Other Canadian generic prefixes include Apo-, pms-, and Sandoz.","difficulty":1,"category":"Pharmacology","topic":"Canadian generics","certification":"PEBC"},
  {"id":"pebc-019","stem":"An IV infusion of 500 mL Normal Saline is ordered to run over 6 hours. What is the flow rate in mL/hr?","options":["50 mL/hr","75 mL/hr","83 mL/hr","100 mL/hr"],"correctIndex":2,"rationale":"Flow rate = Total volume ÷ Time = 500 mL ÷ 6 hours = 83.3 ≈ 83 mL/hr. Canadian hospital pharmacy uses standard IV calculation methods. Electronic infusion pumps are set in mL/hr.","difficulty":1,"category":"Dosage Calculations","topic":"IV flow rates","certification":"PEBC"},
  {"id":"pebc-020","stem":"In Canada, which act governs the regulation of natural health products (NHPs)?","options":["Controlled Drugs and Substances Act","Natural Health Products Regulations","Food and Drugs Act","NAPRA Model Standards"],"correctIndex":1,"rationale":"The Natural Health Products Regulations (under the Food and Drugs Act) govern NHPs in Canada, including vitamins, minerals, herbal remedies, homeopathic medicines, and probiotics. NHPs receive an NPN (Natural Product Number) from Health Canada.","difficulty":2,"category":"Regulations/Law","topic":"natural health products","certification":"PEBC"},
  {"id":"pebc-021","stem":"Which look-alike/sound-alike drug pair is a known safety concern in Canadian pharmacies?","options":["hydrALAZINE and hydrOXYzine","Aspirin and acetaminophen","Metformin and metoprolol","Ibuprofen and naproxen"],"correctIndex":0,"rationale":"hydrALAZINE (antihypertensive) and hydrOXYzine (antihistamine/anxiolytic) are a critical LASA pair in Canadian and US pharmacy practice. ISMP Canada uses Tall Man Lettering to differentiate them. Mix-ups can cause significant patient harm.","difficulty":2,"category":"Medication Safety","topic":"LASA drugs Canada","certification":"PEBC"},
  {"id":"pebc-022","stem":"What is the role of the Ontario College of Pharmacists (OCP)?","options":["Sell medications to the public","Regulate pharmacy practice and protect the public in Ontario","Manufacture generic drugs","Set drug prices"],"correctIndex":1,"rationale":"The OCP is the regulatory body for pharmacy in Ontario. Each province has its own college (e.g., CPBC in British Columbia, OPQ in Quebec). They set practice standards, register pharmacists and technicians, and handle complaints to protect the public.","difficulty":1,"category":"Regulations/Law","topic":"provincial regulatory bodies","certification":"PEBC"},
  {"id":"pebc-023","stem":"A prescription for a narcotic in Canada must include the patient's full address. This requirement comes from which legislation?","options":["NAPRA Model Standards","Controlled Drugs and Substances Act (CDSA)","Personal Health Information Protection Act","Canada Health Act"],"correctIndex":1,"rationale":"The CDSA and its regulations (Narcotic Control Regulations) require narcotic prescriptions to include the patient's name and address, prescriber's name and address, date, drug name and quantity, dosage, and directions. This is more stringent than non-narcotic prescription requirements.","difficulty":2,"category":"Regulations/Law","topic":"narcotic prescriptions","certification":"PEBC"},
  {"id":"pebc-024","stem":"Convert 37°C to Fahrenheit.","options":["96.8°F","98.6°F","100.4°F","102.2°F"],"correctIndex":1,"rationale":"°F = (°C × 9/5) + 32 = (37 × 1.8) + 32 = 66.6 + 32 = 98.6°F. This is normal body temperature. Canadian healthcare uses Celsius, but technicians should know both systems for drug storage and patient assessment contexts.","difficulty":1,"category":"Dosage Calculations","topic":"temperature conversions","certification":"PEBC"},
  {"id":"pebc-025","stem":"Which Canadian organization publishes medication safety alerts and manages incident reporting?","options":["Health Canada","ISMP Canada","Canadian Pharmacists Association","NAPRA"],"correctIndex":1,"rationale":"ISMP Canada (Institute for Safe Medication Practices Canada) is an independent organization that collects and analyzes medication incident reports, publishes safety bulletins, and develops safety recommendations for Canadian healthcare. It is distinct from ISMP US.","difficulty":2,"category":"Medication Safety","topic":"ISMP Canada","certification":"PEBC"},
  {"id":"pebc-026","stem":"A Canadian pharmacy technician receives a faxed prescription for amoxicillin. Under Canadian regulations, is a faxed prescription valid?","options":["No, only original handwritten prescriptions are accepted","Yes, faxed prescriptions are accepted for non-narcotic medications in most provinces","Only if the original is received within 24 hours","Only for refill authorizations"],"correctIndex":1,"rationale":"In most Canadian provinces, faxed prescriptions are accepted for non-narcotic medications as originals. Narcotic prescriptions may have additional requirements. Electronic prescribing (e-prescribing via PrescribeIT) is increasingly used across Canada.","difficulty":2,"category":"Prescription Processing","topic":"faxed prescriptions","certification":"PEBC"},
  {"id":"pebc-027","stem":"What is the brand name for pms-Amlodipine?","options":["Norvasc","Adalat","Cardizem","Plendil"],"correctIndex":0,"rationale":"pms-Amlodipine is a Canadian generic (Pharmascience) of the brand Norvasc (amlodipine). The pms- prefix identifies Pharmascience products. Amlodipine is a dihydropyridine CCB for hypertension and angina.","difficulty":1,"category":"Pharmacology","topic":"Canadian generics","certification":"PEBC"},
  {"id":"pebc-028","stem":"A patient in Canada needs a prescription for methylphenidate. Under the CDSA, methylphenidate is classified as a:","options":["Narcotic","Targeted substance","Controlled drug (Part I)","Uncontrolled substance"],"correctIndex":2,"rationale":"Methylphenidate (Ritalin, Concerta) is a CDSA Part I Controlled Drug in Canada. This classification affects prescribing rules, including requirements for written prescriptions and specific record-keeping. It is not classified as a narcotic under Canadian law.","difficulty":3,"category":"Regulations/Law","topic":"CDSA drug classification","certification":"PEBC"},
  {"id":"pebc-029","stem":"What is the appropriate storage temperature for most vaccines in Canadian pharmacies?","options":["Room temperature (20-25°C)","-20°C","2-8°C (refrigerated)","Below -50°C"],"correctIndex":2,"rationale":"Most vaccines must be stored at 2-8°C (refrigerated) per the National Vaccine Storage and Handling Guidelines for Immunization Providers. Canadian pharmacies must maintain cold chain records and have temperature monitoring devices with min/max recording capabilities.","difficulty":1,"category":"Inventory Management","topic":"vaccine storage Canada","certification":"PEBC"},
  {"id":"pebc-030","stem":"A prescription in Canada calls for Ventolin HFA 100 mcg/dose, 2 puffs QID. How many doses are in one 200-dose canister, and how many days will it last?","options":["100 doses, 12.5 days","200 doses, 25 days","200 doses, 50 days","400 doses, 50 days"],"correctIndex":1,"rationale":"200 doses in the canister. Patient uses 2 puffs × 4 times daily = 8 puffs/day. Days = 200 ÷ 8 = 25 days. Ventolin (salbutamol in Canada, albuterol in US) is a rescue bronchodilator.","difficulty":2,"category":"Dosage Calculations","topic":"inhaler day supply","certification":"PEBC"},
  {"id":"pebc-031","stem":"In Canadian pharmacy, what does PIPEDA govern?","options":["Drug pricing regulations","Personal health information privacy in the private sector","Controlled substance scheduling","Pharmacy technician registration"],"correctIndex":1,"rationale":"PIPEDA (Personal Information Protection and Electronic Documents Act) is federal privacy legislation governing the collection, use, and disclosure of personal information (including health information) in the private sector in Canada. Provincial privacy laws may also apply (e.g., PHIPA in Ontario).","difficulty":2,"category":"Regulations/Law","topic":"privacy legislation Canada","certification":"PEBC"},
  {"id":"pebc-032","stem":"What is the difference between salbutamol (Canadian name) and albuterol (US name)?","options":["They are completely different drugs","They are the same drug with different international names","Salbutamol is a longer-acting version","Albuterol is available OTC but salbutamol is not"],"correctIndex":1,"rationale":"Salbutamol (INN/Canadian name) and albuterol (USAN/US name) are the same beta-2 agonist bronchodilator. Canada uses International Nonproprietary Names (INN), while the US uses United States Adopted Names (USAN). Brand name: Ventolin in both countries.","difficulty":1,"category":"Pharmacology","topic":"INN vs USAN names","certification":"PEBC"},
  {"id":"pebc-033","stem":"A Canadian pharmacy dispenses methadone for opioid use disorder. Under the CDSA, methadone is classified as:","options":["A targeted substance","A Schedule I narcotic","A benzodiazepine","An unscheduled drug"],"correctIndex":1,"rationale":"Methadone is a CDSA Schedule I narcotic in Canada. Prescribing methadone for opioid use disorder requires a Section 56 exemption from Health Canada. It is dispensed under strict supervision, often requiring daily witnessed ingestion.","difficulty":3,"category":"Regulations/Law","topic":"methadone regulations Canada","certification":"PEBC"},
  {"id":"pebc-034","stem":"How many mL of a 25% stock solution are needed to prepare 200 mL of a 5% solution?","options":["20 mL","40 mL","50 mL","100 mL"],"correctIndex":1,"rationale":"Using C1V1 = C2V2: 25% × V1 = 5% × 200 mL. V1 = 1000 ÷ 25 = 40 mL of the 25% stock solution. Add purified water to reach 200 mL total volume. This dilution calculation is standard in Canadian pharmacy compounding.","difficulty":2,"category":"Dosage Calculations","topic":"dilution calculations","certification":"PEBC"},
  {"id":"pebc-035","stem":"In Canada, pharmacy technicians are regulated professionals. What does 'regulated' mean in this context?","options":["They can prescribe medications","They are registered with a provincial regulatory college and must meet practice standards","They are employees of Health Canada","They can counsel patients on medication use"],"correctIndex":1,"rationale":"Regulated pharmacy technicians in Canada are registered with their provincial college (e.g., OCP in Ontario, CPBC in BC). They must pass the PEBC qualifying exam, meet continuing education requirements, and practice within defined scope. Regulation protects the public.","difficulty":1,"category":"Regulations/Law","topic":"pharmacy technician regulation","certification":"PEBC"},
  {"id":"pebc-036","stem":"Which Canadian-specific drug interaction is important with warfarin and cranberry juice?","options":["Cranberry juice has no effect on warfarin","Cranberry juice may inhibit CYP2C9, increasing warfarin effect and bleeding risk","Cranberry juice increases warfarin metabolism","Cranberry juice binds warfarin in the gut"],"correctIndex":1,"rationale":"Cranberry juice may inhibit CYP2C9 and increase the anticoagulant effect of warfarin. Health Canada and ISMP Canada have issued advisories about this interaction. Patients on warfarin should limit cranberry product consumption and report changes to their pharmacist.","difficulty":3,"category":"Drug Interactions","topic":"food-drug interactions","certification":"PEBC"},
  {"id":"pebc-037","stem":"What is the brand name for Teva-Omeprazole?","options":["Prilosec","Losec","Nexium","Prevacid"],"correctIndex":1,"rationale":"In Canada, the brand name for omeprazole is Losec (not Prilosec as in the US). Teva-Omeprazole is a Canadian generic. Nexium is esomeprazole, Prevacid is lansoprazole. Canadian and US brand names sometimes differ for the same molecule.","difficulty":2,"category":"Pharmacology","topic":"Canadian brand names","certification":"PEBC"},
  {"id":"pebc-038","stem":"A patient in Quebec presents a prescription from an Ontario physician. Can a Quebec pharmacy fill it?","options":["No, prescriptions cannot cross provincial lines","Yes, but only if the prescriber verifies by phone","Yes, interprovincial prescriptions are generally accepted for non-narcotic medications","Only for emergency supplies"],"correctIndex":2,"rationale":"Interprovincial prescriptions are generally accepted across Canada for non-narcotic medications, though the pharmacist may verify with the prescriber. Some provinces have specific requirements for out-of-province prescriptions. Narcotics may have additional restrictions.","difficulty":2,"category":"Prescription Processing","topic":"interprovincial prescriptions","certification":"PEBC"},
  {"id":"pebc-039","stem":"A hospital pharmacy in Canada prepares TPN. What is the caloric value of dextrose per gram?","options":["3.4 kcal/g","4 kcal/g","9 kcal/g","7 kcal/g"],"correctIndex":0,"rationale":"IV dextrose provides 3.4 kcal/g (not the standard 4 kcal/g for oral carbohydrates, because IV dextrose is the monohydrate form). Amino acids provide 4 kcal/g, and lipids provide 9-10 kcal/g. This is tested on the PEBC exam.","difficulty":3,"category":"Dosage Calculations","topic":"TPN calculations","certification":"PEBC"},
  {"id":"pebc-040","stem":"Under NAPRA Model Standards, what tasks can a regulated pharmacy technician perform independently?","options":["Counsel patients on drug interactions","Perform final check on prescriptions in all provinces","Receive and technically process prescriptions, perform product preparation","Prescribe medications for minor ailments"],"correctIndex":2,"rationale":"Regulated pharmacy technicians in Canada can receive prescriptions, enter data, prepare products, and perform technical check (in provinces that allow tech-check-tech). They cannot counsel patients, perform final clinical verification, or prescribe.","difficulty":2,"category":"Regulations/Law","topic":"scope of practice","certification":"PEBC"},
  {"id":"pebc-041","stem":"What is the generic name for Sandoz Amlodipine?","options":["Diltiazem","Amlodipine","Nifedipine","Verapamil"],"correctIndex":1,"rationale":"Sandoz Amlodipine is a Canadian generic manufactured by Sandoz Canada. Amlodipine is a dihydropyridine calcium channel blocker. Sandoz is one of the major generic manufacturers in Canada. The 'Sandoz' prefix identifies their products.","difficulty":1,"category":"Pharmacology","topic":"Canadian generics","certification":"PEBC"},
  {"id":"pebc-042","stem":"A patient is prescribed insulin glargine 24 units SubQ QHS. The pen contains 300 units/3 mL. How many pens are needed for a 30-day supply?","options":["1 pen","2 pens","3 pens","4 pens"],"correctIndex":2,"rationale":"Total units needed: 24 units/day × 30 days = 720 units. Each pen: 300 units. Pens needed: 720 ÷ 300 = 2.4, rounded up to 3 pens. In Canadian practice, insulin pens are standard for outpatient use.","difficulty":2,"category":"Dosage Calculations","topic":"insulin pen calculations","certification":"PEBC"},
  {"id":"pebc-043","stem":"Which Canadian legislation requires pharmacies to maintain records of narcotic dispensing for a minimum of 2 years?","options":["Canada Health Act","Controlled Drugs and Substances Act","PIPEDA","Natural Health Products Regulations"],"correctIndex":1,"rationale":"The CDSA and its Narcotic Control Regulations require pharmacies to maintain records of narcotic transactions for a minimum of 2 years. Records must be available for inspection by Health Canada inspectors. Some provinces require longer retention periods.","difficulty":2,"category":"Regulations/Law","topic":"record keeping Canada","certification":"PEBC"},
  {"id":"pebc-044","stem":"Which of the following is a commonly prescribed Canadian combination product for hypertension?","options":["Vaseretic (enalapril/HCTZ)","Hyzaar (losartan/HCTZ)","Atacand Plus (candesartan/HCTZ)","All of the above"],"correctIndex":3,"rationale":"All three are commonly prescribed combination antihypertensives available in Canada. Canadian formularies include many ARB/HCTZ and ACE inhibitor/HCTZ combinations. Pharmacy technicians should recognize both the combination and individual components.","difficulty":2,"category":"Pharmacology","topic":"combination products","certification":"PEBC"},
  {"id":"pebc-045","stem":"In Canadian pharmacy practice, what is 'tech-check-tech'?","options":["A computer system for ordering drugs","A process where a regulated technician checks another technician's work for accuracy","A method of counting controlled substances","A prescription verification app"],"correctIndex":1,"rationale":"Tech-check-tech allows a regulated pharmacy technician to perform the final product check (accuracy of drug, strength, quantity, labeling) on another technician's dispensing work. This frees the pharmacist for clinical activities. Not all provinces have implemented this.","difficulty":2,"category":"Prescription Processing","topic":"tech-check-tech","certification":"PEBC"},
  {"id":"pebc-046","stem":"A patient brings a prescription for acetaminophen with codeine 300/30 mg from another province. What CDSA classification applies?","options":["It is unscheduled","It is a narcotic preparation requiring a prescription","It is a targeted substance","It does not fall under the CDSA"],"correctIndex":1,"rationale":"Acetaminophen with codeine 30 mg is a narcotic preparation under the CDSA (higher dose codeine combinations require prescriptions). Only products with ≤8 mg codeine plus two other active ingredients may be available without a prescription in some provinces.","difficulty":2,"category":"Regulations/Law","topic":"codeine scheduling Canada","certification":"PEBC"},
  {"id":"pebc-047","stem":"What is the brand name for epinephrine auto-injectors most commonly dispensed in Canada?","options":["EpiPen","Auvi-Q","SYMJEPI","Adrenaclick"],"correctIndex":0,"rationale":"EpiPen is the most commonly dispensed epinephrine auto-injector in Canada. It is available in 0.15 mg (Jr) and 0.3 mg doses. Pharmacy technicians must ensure proper storage (15-25°C, protected from light) and check expiration dates. Allerject is the Canadian equivalent of Auvi-Q.","difficulty":1,"category":"Pharmacology","topic":"emergency medications","certification":"PEBC"},
  {"id":"pebc-048","stem":"Calculate the number of 500 mg capsules needed to compound 60 g of a powder formulation.","options":["60 capsules","100 capsules","120 capsules","150 capsules"],"correctIndex":2,"rationale":"60 g = 60,000 mg. Number of capsules = 60,000 mg ÷ 500 mg/capsule = 120 capsules. This is a straightforward compounding calculation common in Canadian pharmacy practice.","difficulty":1,"category":"Dosage Calculations","topic":"capsule calculations","certification":"PEBC"},
  {"id":"pebc-049","stem":"In Canada, which organization administers the qualifying examination for pharmacy technicians?","options":["NAPRA","Health Canada","PEBC (Pharmacy Examining Board of Canada)","Provincial Colleges of Pharmacy"],"correctIndex":2,"rationale":"The PEBC administers the Qualifying Examination for Pharmacy Technicians in Canada. Candidates must pass both the Multiple Choice Questions (MCQ) and the Objective Structured Performance Examination (OSPE) components. Provincial registration follows successful completion.","difficulty":1,"category":"Regulations/Law","topic":"PEBC exam","certification":"PEBC"},
  {"id":"pebc-050","stem":"Which error prevention strategy does ISMP Canada specifically recommend for high-alert medications in Canadian hospitals?","options":["Color-coded labels only","Independent double checks for high-alert medications","Verbal orders for all medications","Using abbreviations to speed dispensing"],"correctIndex":1,"rationale":"ISMP Canada recommends independent double checks for high-alert medications including insulin, heparin, opioids, neuromuscular blocking agents, and concentrated electrolytes. This means a second person independently verifies the preparation without knowing the first person's result.","difficulty":2,"category":"Medication Safety","topic":"independent double checks","certification":"PEBC"},
  {"id":"pebc-051","stem":"What does the term 'interchangeable' mean when a Canadian provincial formulary lists a generic drug?","options":["The drug can be used for any indication","The generic can be substituted for the brand without prescriber authorization","The drug can be transferred between pharmacies","The drug is available in all provinces"],"correctIndex":1,"rationale":"In Canadian pharmacy, 'interchangeable' means a generic product has been declared therapeutically equivalent by the provincial authority and may be substituted for the brand name product without prescriber authorization, unless the prescriber writes 'no substitution.'","difficulty":1,"category":"Prescription Processing","topic":"generic substitution Canada","certification":"PEBC"},
  {"id":"pebc-052","stem":"A Canadian pharmacy receives a prescription for Suboxone (buprenorphine/naloxone). What special requirements apply?","options":["No special requirements, it is unscheduled","The prescriber must have a CDSA Section 56 exemption for buprenorphine","Only hospital pharmacies can dispense it","It must be compounded from individual ingredients"],"correctIndex":1,"rationale":"In Canada, buprenorphine for opioid use disorder required prescribers to have a Section 56 exemption under the CDSA (this requirement was removed in some provinces for buprenorphine/naloxone specifically). Pharmacy technicians must verify prescriber authorization and follow provincial guidelines.","difficulty":3,"category":"Regulations/Law","topic":"opioid agonist therapy","certification":"PEBC"},
  {"id":"pebc-053","stem":"Which antibiotic is commonly known as 'Apo-Amoxicillin' in Canadian pharmacy?","options":["Ampicillin","Amoxicillin","Amoxicillin-clavulanate","Azithromycin"],"correctIndex":1,"rationale":"Apo-Amoxicillin is a Canadian generic form of amoxicillin manufactured by Apotex Inc. The 'Apo-' prefix is Apotex's trademark for their generic products. Amoxicillin is a widely prescribed penicillin-type antibiotic for bacterial infections.","difficulty":1,"category":"Pharmacology","topic":"Canadian generics","certification":"PEBC"},
  {"id":"pebc-054","stem":"A prescription reads: '1 tab PO QAM ac.' What does 'QAM ac' mean?","options":["Every morning after meals","Every morning before meals","Every afternoon with meals","At bedtime after eating"],"correctIndex":1,"rationale":"QAM = every morning (quaque ante meridiem). ac = before meals (ante cibum). The patient should take one tablet by mouth every morning before eating. This sig code combination is commonly tested on the PEBC exam.","difficulty":1,"category":"Prescription Processing","topic":"sig codes","certification":"PEBC"},
  {"id":"pebc-055","stem":"What is the Canadian Compendium of Pharmaceuticals and Specialties (CPS) used for?","options":["Setting drug prices","As a comprehensive drug reference for healthcare professionals","Ordering controlled substances","Patient education handouts only"],"correctIndex":1,"rationale":"The CPS is the authoritative Canadian drug reference published by the Canadian Pharmacists Association (CPhA). It contains Health Canada-approved monographs, dosing information, interactions, and safety data. It is the Canadian equivalent of the US Drug Facts and Comparisons.","difficulty":1,"category":"Prescription Processing","topic":"drug references Canada","certification":"PEBC"},
  {"id":"pebc-056","stem":"If a Canadian pharmacy needs 2 L of a 0.45% NaCl solution, how many grams of NaCl are required?","options":["0.9 g","4.5 g","9 g","45 g"],"correctIndex":2,"rationale":"0.45% = 0.45 g/100 mL. For 2 L (2000 mL): 0.45 × (2000/100) = 0.45 × 20 = 9 g of NaCl. Half-normal saline (0.45% NaCl) is a hypotonic IV solution used for hydration.","difficulty":2,"category":"Dosage Calculations","topic":"solution preparation","certification":"PEBC"},
  {"id":"pebc-057","stem":"In Canadian pharmacy practice, which document standardizes the scope of practice for pharmacy technicians across provinces?","options":["Canada Health Act","NAPRA Model Standards of Practice for Pharmacy Technicians","CDSA Regulations","Provincial Health Insurance Acts"],"correctIndex":1,"rationale":"NAPRA's Model Standards of Practice for Pharmacy Technicians provides a national framework for pharmacy technician practice in Canada. Individual provinces adapt these standards through their regulatory colleges. Standards cover competencies, ethics, and professional responsibilities.","difficulty":2,"category":"Regulations/Law","topic":"practice standards","certification":"PEBC"},
  {"id":"pebc-058","stem":"What is the Canadian term for what the US calls 'legend drugs'?","options":["Ethical drugs","Schedule I drugs (NAPRA)","Prescription drugs / Schedule F drugs","Controlled substances"],"correctIndex":2,"rationale":"In Canada, 'prescription drugs' or drugs listed in Schedule F of the Food and Drug Regulations (now the Prescription Drug List) are equivalent to US 'legend drugs.' They require a prescription from an authorized prescriber. NAPRA Schedule I also refers to prescription-only drugs.","difficulty":2,"category":"Regulations/Law","topic":"prescription drug terminology","certification":"PEBC"},
  {"id":"pebc-059","stem":"A patient weighs 60 kg and is prescribed vancomycin at 15 mg/kg IV q12h. The available vial is 1 g/20 mL after reconstitution. What volume per dose?","options":["9 mL","12 mL","18 mL","20 mL"],"correctIndex":2,"rationale":"Dose: 15 mg/kg × 60 kg = 900 mg. Concentration: 1 g/20 mL = 1000 mg/20 mL = 50 mg/mL. Volume: 900 mg ÷ 50 mg/mL = 18 mL. Vancomycin requires therapeutic drug monitoring in Canadian hospitals.","difficulty":3,"category":"Dosage Calculations","topic":"IV drug calculations","certification":"PEBC"},
  {"id":"pebc-060","stem":"Which provincial legislation in Ontario specifically governs pharmacy practice?","options":["Drug and Pharmacies Regulation Act (DPRA)","Canada Health Act","Controlled Drugs and Substances Act","Personal Health Information Protection Act"],"correctIndex":0,"rationale":"The Drug and Pharmacies Regulation Act (DPRA) governs pharmacy practice in Ontario, including pharmacy operations, technician registration, and dispensing requirements. Each province has its own pharmacy legislation (e.g., Pharmacy Operations and Drug Scheduling Act in BC).","difficulty":2,"category":"Regulations/Law","topic":"Ontario pharmacy law","certification":"PEBC"},
  {"id":"pebc-061","stem":"A prescription reads: 'Clavulin 500/125 mg PO TID × 10 days.' What is Clavulin known as in the US?","options":["Augmentin","Unasyn","Zosyn","Timentin"],"correctIndex":0,"rationale":"Clavulin is the Canadian brand name for amoxicillin/clavulanic acid, known as Augmentin in the US. Unasyn is ampicillin/sulbactam (IV), Zosyn is piperacillin/tazobactam (IV). Knowing Canadian vs US brand names is important for the PEBC exam.","difficulty":2,"category":"Pharmacology","topic":"Canadian vs US brand names","certification":"PEBC"},
  {"id":"pebc-062","stem":"What is the primary purpose of MedEffect Canada?","options":["Drug pricing database","Adverse drug reaction reporting system","Pharmacy licensing portal","Drug procurement system"],"correctIndex":1,"rationale":"MedEffect Canada is Health Canada's adverse drug reaction (ADR) reporting system, equivalent to the US FDA MedWatch. Healthcare professionals and consumers can report suspected ADRs, medical device incidents, and other health product safety concerns.","difficulty":2,"category":"Medication Safety","topic":"ADR reporting Canada","certification":"PEBC"},
  {"id":"pebc-063","stem":"How do Canadian pharmacies handle drug recalls differently from normal returns?","options":["No difference in process","Recalled products are quarantined immediately, and dispensing records are checked to notify affected patients","Recalled products are simply discarded","Recalled products are returned to the wholesaler with regular returns"],"correctIndex":1,"rationale":"In Canada, recalled products must be immediately quarantined (removed from dispensing stock), patients who received affected lots must be identified and notified, and the recall must be documented. Health Canada issues recall notices through the Health Product InfoWatch and MedEffect systems.","difficulty":2,"category":"Inventory Management","topic":"recall procedures Canada","certification":"PEBC"},
  {"id":"pebc-064","stem":"A patient in British Columbia uses PharmaCare. What is PharmaCare?","options":["A private insurance company","BC's provincial drug benefit program","A pharmacy chain","A medication management app"],"correctIndex":1,"rationale":"PharmaCare is British Columbia's provincial drug benefit program, covering eligible residents for prescription medications. Plans include Fair PharmaCare (income-based), Plan B (RCMP), Plan C (social assistance), and others. Each province has its own equivalent program.","difficulty":1,"category":"Prescription Processing","topic":"provincial drug plans","certification":"PEBC"},
  {"id":"pebc-065","stem":"A cream formula requires 15 g of zinc oxide in 100 g of base. What is the percentage strength?","options":["0.15%","1.5%","15%","150%"],"correctIndex":2,"rationale":"Percentage w/w = (weight of solute ÷ total weight) × 100 = (15 g ÷ 100 g) × 100 = 15%. This is a basic percent strength calculation used in Canadian compounding practice.","difficulty":1,"category":"Dosage Calculations","topic":"percentage calculations","certification":"PEBC"},
  {"id":"pebc-066","stem":"In Canada, what is a 'verbal prescription order'?","options":["A prescription written in plain language","A prescription communicated orally by the prescriber to the pharmacist","A patient's verbal request for an OTC drug","A voicemail left by the prescriber"],"correctIndex":1,"rationale":"A verbal prescription order is when a prescriber communicates a prescription orally (by phone or in person) to the pharmacist. In Canada, verbal orders are accepted for most medications but are restricted or prohibited for narcotics in most provinces. The pharmacist must document the verbal order.","difficulty":1,"category":"Prescription Processing","topic":"verbal orders","certification":"PEBC"},
  {"id":"pebc-067","stem":"Which of the following is NOT a role of the pharmacy technician under NAPRA Model Standards?","options":["Receiving and transcribing prescriptions","Performing final clinical verification of prescriptions","Preparing and packaging medications","Maintaining accurate inventory records"],"correctIndex":1,"rationale":"Final clinical verification (therapeutic appropriateness, drug interactions, clinical assessment) is a pharmacist-only responsibility. Pharmacy technicians handle technical tasks: receiving prescriptions, data entry, product preparation, packaging, labeling, and inventory management.","difficulty":1,"category":"Regulations/Law","topic":"scope of practice","certification":"PEBC"},
  {"id":"pebc-068","stem":"A hospital patient is prescribed heparin 25,000 units in 500 mL D5W at 1200 units/hour. What is the infusion rate?","options":["12 mL/hr","24 mL/hr","48 mL/hr","60 mL/hr"],"correctIndex":1,"rationale":"Concentration: 25,000 units/500 mL = 50 units/mL. Rate: 1200 units/hr ÷ 50 units/mL = 24 mL/hr. Heparin is a high-alert medication; dose calculations must be independently double-checked per ISMP Canada guidelines.","difficulty":3,"category":"Dosage Calculations","topic":"heparin calculations","certification":"PEBC"},
  {"id":"pebc-069","stem":"What distinguishes a Canadian NHP (Natural Health Product) from a pharmaceutical drug?","options":["NHPs are not regulated","NHPs receive an NPN instead of a DIN and follow the Natural Health Products Regulations","NHPs are prescription-only","NHPs are manufactured differently but have the same regulatory pathway"],"correctIndex":1,"rationale":"Canadian NHPs are regulated separately under the Natural Health Products Regulations. They receive a Natural Product Number (NPN) or Homeopathic Medicine Number (DIN-HM) instead of a DIN. NHPs include vitamins, minerals, herbs, and traditional medicines.","difficulty":2,"category":"Regulations/Law","topic":"NHP regulations","certification":"PEBC"},
  {"id":"pebc-070","stem":"A prescription reads: 'Synthroid 0.05 mg PO daily.' Convert this dose to micrograms.","options":["5 mcg","50 mcg","500 mcg","5000 mcg"],"correctIndex":1,"rationale":"0.05 mg × 1000 mcg/mg = 50 mcg. Levothyroxine (Synthroid) is typically dosed in mcg (25, 50, 75, 88, 100, 112, 125, 137, 150, 175, 200, 300 mcg). Converting between mg and mcg prevents 10-fold or 1000-fold dosing errors.","difficulty":1,"category":"Dosage Calculations","topic":"unit conversions","certification":"PEBC"},
  {"id":"pebc-071","stem":"In Canada, PrescribeIT is used for:","options":["Ordering controlled substances from Health Canada","Electronic prescribing between prescribers and pharmacies","Patient medication reminders","Drug recall notifications"],"correctIndex":1,"rationale":"PrescribeIT is Canada's national electronic prescribing (e-prescribing) service that enables prescribers to transmit prescriptions electronically to a patient's pharmacy of choice. It improves prescription accuracy and reduces errors from illegible handwriting.","difficulty":2,"category":"Prescription Processing","topic":"e-prescribing Canada","certification":"PEBC"},
  {"id":"pebc-072","stem":"A patient asks the pharmacy technician about drug side effects. What is the appropriate response?","options":["Provide detailed counseling on all side effects","Explain common side effects and management strategies","Refer the patient to the pharmacist for medication counseling","Tell the patient to look it up online"],"correctIndex":2,"rationale":"In Canada, medication counseling is a pharmacist responsibility, not within the pharmacy technician's scope of practice. The technician should politely redirect the patient to the pharmacist for questions about side effects, interactions, or medication use.","difficulty":1,"category":"Medication Safety","topic":"scope of practice","certification":"PEBC"},
  {"id":"pebc-073","stem":"What is the alligation calculation to mix 95% ethanol and 50% ethanol to prepare 1 L of 70% ethanol?","options":["444 mL of 95% + 556 mL of 50%","556 mL of 95% + 444 mL of 50%","500 mL of each","700 mL of 95% + 300 mL of 50%"],"correctIndex":0,"rationale":"95% gives (70-50) = 20 parts. 50% gives (95-70) = 25 parts. Total = 45 parts. 95% needed: (20/45) × 1000 = 444 mL. 50% needed: (25/45) × 1000 = 556 mL. Verify: (444×0.95 + 556×0.50)/1000 = (421.8 + 278)/1000 = 699.8/1000 ≈ 70%.","difficulty":4,"category":"Dosage Calculations","topic":"alligation","certification":"PEBC"},
  {"id":"pebc-074","stem":"What is the purpose of a 'medication incident report' in Canadian healthcare settings?","options":["To discipline the healthcare worker involved","To document and learn from medication errors for system improvement","To bill insurance for the error","To remove the technician's registration"],"correctIndex":1,"rationale":"Medication incident reports in Canadian healthcare are used for system improvement, not punishment. They help identify system failures, process gaps, and opportunities for safer practice. ISMP Canada promotes a 'just culture' approach to incident reporting.","difficulty":1,"category":"Medication Safety","topic":"incident reporting","certification":"PEBC"},
  {"id":"pebc-075","stem":"How many milligrams of active drug are in 500 mL of a 1:5000 solution?","options":["0.1 mg","1 mg","10 mg","100 mg"],"correctIndex":3,"rationale":"1:5000 means 1 g in 5000 mL. For 500 mL: (1 g / 5000 mL) × 500 mL = 0.1 g = 100 mg. Ratio strength is commonly used in Canadian pharmacy for dilute solutions.","difficulty":3,"category":"Dosage Calculations","topic":"ratio strength","certification":"PEBC"},
  {"id":"pebc-076","stem":"In Canadian pharmacy, what does 'formulary' mean?","options":["A compounding recipe book","A list of drugs approved for coverage by an insurance plan or institution","A regulatory document listing banned substances","A pharmacist's personal drug reference"],"correctIndex":1,"rationale":"A formulary is a list of medications approved for coverage by a drug plan (provincial or private insurance) or an institution (hospital). In Canada, each province maintains a formulary for its public drug plan. Non-formulary drugs may not be covered or require special authorization.","difficulty":1,"category":"Prescription Processing","topic":"formulary management","certification":"PEBC"},
  {"id":"pebc-077","stem":"Which Canadian law requires that all drugs sold in Canada have a DIN?","options":["Controlled Drugs and Substances Act","Food and Drugs Act and Regulations","Canada Health Act","Patent Act"],"correctIndex":1,"rationale":"The Food and Drugs Act and its regulations require that all pharmaceutical drugs sold in Canada have a Drug Identification Number (DIN) assigned by Health Canada. The DIN indicates the product has been reviewed and approved for safety, efficacy, and quality.","difficulty":2,"category":"Regulations/Law","topic":"drug approval Canada","certification":"PEBC"},
  {"id":"pebc-078","stem":"A prescription in Canada is written for 'Losec 20 mg PO daily.' A US-trained pharmacist might not recognize Losec. What is the equivalent US brand name?","options":["Prilosec","Prevacid","Protonix","Nexium"],"correctIndex":0,"rationale":"Losec is the Canadian brand name for omeprazole; Prilosec is the US brand name. Both contain the same active ingredient. This difference in brand naming between countries is an important consideration for internationally trained pharmacy professionals.","difficulty":2,"category":"Pharmacology","topic":"Canadian vs US brand names","certification":"PEBC"},
  {"id":"pebc-079","stem":"A Canadian patient has both a provincial drug plan and private insurance. How are claims typically processed?","options":["Only the provincial plan is billed","Only the private insurance is billed","The provincial plan is billed first, then the private plan covers the remaining cost","The patient pays the full cost and submits claims later"],"correctIndex":2,"rationale":"In Canada, provincial drug plans are typically the first payer. Private insurance then covers some or all of the remaining cost (copayment, deductible). This coordination of benefits ensures the patient pays the least out-of-pocket amount. The order of billing matters.","difficulty":2,"category":"Prescription Processing","topic":"insurance coordination Canada","certification":"PEBC"},
  {"id":"pebc-080","stem":"What is a 'targeted substance' under the CDSA?","options":["A drug targeted for removal from the market","A substance in CDSA Schedule IV, including benzodiazepines","A drug under special surveillance by Health Canada","A substance used only in hospitals"],"correctIndex":1,"rationale":"Targeted substances are in CDSA Schedule IV and include benzodiazepines (diazepam, lorazepam, alprazolam), barbiturates, and anabolic steroids. They have specific prescribing and record-keeping requirements distinct from narcotics and controlled drugs.","difficulty":3,"category":"Regulations/Law","topic":"targeted substances","certification":"PEBC"},
  {"id":"pebc-081","stem":"Calculate the day supply for a prescription: Metoprolol 50 mg, #180, Sig: i tab PO BID.","options":["30 days","60 days","90 days","180 days"],"correctIndex":2,"rationale":"BID = 2 tablets/day. Day supply = 180 tablets ÷ 2 tablets/day = 90 days. This is a standard dispensing quantity for a 3-month supply of a chronic medication in Canadian pharmacy practice.","difficulty":1,"category":"Dosage Calculations","topic":"day supply calculations","certification":"PEBC"},
  {"id":"pebc-082","stem":"What is the role of the Canadian Institute for Health Information (CIHI) in pharmacy?","options":["It regulates pharmacy practice","It provides drug safety warnings","It collects and analyzes health data including drug utilization statistics","It licenses pharmacy technicians"],"correctIndex":2,"rationale":"CIHI collects and analyzes health data across Canada, including the National Prescription Drug Utilization Information System (NPDUIS). This data helps inform drug policy, identify prescribing trends, and support evidence-based decision-making.","difficulty":2,"category":"Regulations/Law","topic":"health data organizations","certification":"PEBC"},
  {"id":"pebc-083","stem":"A pharmacy technician in Alberta discovers a discrepancy in the narcotic count. What is the first step?","options":["Adjust the count and continue working","Notify the pharmacist in charge immediately","Report directly to Health Canada","Wait until end of shift to investigate"],"correctIndex":1,"rationale":"Any narcotic discrepancy must be immediately reported to the pharmacist in charge. The pharmacist will investigate, document the discrepancy, and if theft or loss is suspected, report to Health Canada and local law enforcement as required by the CDSA.","difficulty":1,"category":"Medication Safety","topic":"narcotic discrepancies","certification":"PEBC"},
  {"id":"pebc-084","stem":"What is the standard concentration of Normal Saline used in Canadian hospitals?","options":["0.45% NaCl","0.9% NaCl","3% NaCl","5% NaCl"],"correctIndex":1,"rationale":"Normal Saline (NS) is 0.9% NaCl (9 g NaCl per 1000 mL), an isotonic solution. This is the same standard worldwide. Half-normal saline is 0.45% (hypotonic), and 3% NaCl is hypertonic saline.","difficulty":1,"category":"Sterile Products","topic":"IV solutions","certification":"PEBC"},
  {"id":"pebc-085","stem":"A prescription for a benzodiazepine in Canada can have a maximum of how many refills in most provinces?","options":["No refills allowed","Up to 5 refills","As specified by the prescriber, typically within 1 year","Unlimited refills"],"correctIndex":2,"rationale":"Benzodiazepines (targeted substances, CDSA Schedule IV) in Canada can be refilled as specified by the prescriber, typically valid for up to 1 year from the date written. Refill rules vary by province. Narcotics (CDSA Schedule I) cannot be refilled in most provinces.","difficulty":2,"category":"Regulations/Law","topic":"refill rules Canada","certification":"PEBC"},
  {"id":"pebc-086","stem":"Which Canadian drug reference is known as the 'orange book equivalent' for interchangeability?","options":["CPS","Provincial formulary interchangeability lists","Health Canada Product Monographs","Therapeutic Products Directorate database"],"correctIndex":1,"rationale":"Provincial formulary interchangeability lists (e.g., Ontario's Interchangeable Drug Products Formulary) serve a similar purpose to the US FDA Orange Book, identifying generic products that are therapeutically equivalent and can be substituted for brand-name drugs.","difficulty":3,"category":"Prescription Processing","topic":"generic interchangeability","certification":"PEBC"},
  {"id":"pebc-087","stem":"A patient needs 10 mL of a 2% lidocaine solution for a dental procedure. How many mg of lidocaine is this?","options":["2 mg","20 mg","200 mg","2000 mg"],"correctIndex":2,"rationale":"2% = 2 g/100 mL = 20 mg/mL. In 10 mL: 20 mg/mL × 10 mL = 200 mg. This concentration calculation is essential for local anesthetic dosing in Canadian dental and medical practice.","difficulty":2,"category":"Dosage Calculations","topic":"local anesthetic calculations","certification":"PEBC"},
  {"id":"pebc-088","stem":"What does 'adaption' or 'adaptation' of a prescription mean in Canadian pharmacy practice?","options":["Changing the drug to a different class","A pharmacist altering certain aspects of a prescription within their authority (e.g., extending refills, changing dosage form)","Converting a prescription to metric units","Translating a prescription from French to English"],"correctIndex":1,"rationale":"Prescription adaptation/adaption in Canada allows pharmacists to make certain changes to prescriptions within their authority, such as extending refills for continuity of care, changing dosage forms (tablet to liquid), or making therapeutic substitutions. Rules vary by province.","difficulty":2,"category":"Prescription Processing","topic":"prescription adaptation","certification":"PEBC"},
  {"id":"pebc-089","stem":"In Canada, what is the 'Exceptional Access Program' (EAP) in Ontario?","options":["A program for free drug samples","A process for obtaining coverage for drugs not on the provincial formulary","A training program for pharmacy technicians","A discount drug purchasing program"],"correctIndex":1,"rationale":"Ontario's Exceptional Access Program (EAP) allows prescribers to request coverage for drugs not on the Ontario Drug Benefit formulary or for non-listed indications. Similar programs exist in other provinces (Special Authorization in BC, Patient Support Programs in other provinces).","difficulty":2,"category":"Prescription Processing","topic":"special authorization","certification":"PEBC"},
  {"id":"pebc-090","stem":"Which of the following statements about cannabis in Canadian pharmacy is correct?","options":["Cannabis is Schedule I under the CDSA and cannot be dispensed","Cannabis for medical purposes is regulated under the Cannabis Act and can be obtained from licensed sellers","Only pharmacies can sell recreational cannabis","Cannabis is unregulated in Canada"],"correctIndex":1,"rationale":"Since the Cannabis Act (2018), medical cannabis in Canada is regulated separately from the CDSA. It can be obtained from licensed sellers authorized by Health Canada. Recreational cannabis is legal but sold through provincial retail channels, not typically pharmacies.","difficulty":2,"category":"Regulations/Law","topic":"cannabis regulations Canada","certification":"PEBC"},
  {"id":"pebc-091","stem":"A patient asks about acetaminophen dose limits. In Canada, what is the recommended maximum daily dose for a healthy adult?","options":["2000 mg","3000 mg","4000 mg","5000 mg"],"correctIndex":2,"rationale":"The maximum recommended daily dose of acetaminophen for healthy adults in Canada is 4000 mg (4 g), consistent with international guidelines. Health Canada has issued advisories about liver toxicity risk, especially with concurrent alcohol use or in patients with liver disease. Some Canadian guidelines recommend lower limits (3000 mg/day).","difficulty":1,"category":"Medication Safety","topic":"dose limits","certification":"PEBC"},
  {"id":"pebc-092","stem":"What is the volume needed to administer 750 mg of cefazolin from a vial reconstituted to 250 mg/mL?","options":["1 mL","2 mL","3 mL","5 mL"],"correctIndex":2,"rationale":"Volume = Dose ÷ Concentration = 750 mg ÷ 250 mg/mL = 3 mL. Cefazolin is a commonly used first-generation cephalosporin for surgical prophylaxis and infections in Canadian hospitals.","difficulty":1,"category":"Dosage Calculations","topic":"reconstitution calculations","certification":"PEBC"},
  {"id":"pebc-093","stem":"In Canadian pharmacy, what is a 'blister pack' or 'compliance pack'?","options":["Packaging for emergency medications","Multi-dose packaging organized by day and time to improve adherence","A type of controlled substance packaging","Packaging used only for hospital medications"],"correctIndex":1,"rationale":"Blister packs (compliance packs/pouch packaging) organize medications by day and administration time (morning, noon, evening, bedtime) to improve adherence. They are commonly prepared by Canadian community pharmacies for elderly patients and those on multiple medications.","difficulty":1,"category":"Prescription Processing","topic":"compliance packaging","certification":"PEBC"},
  {"id":"pebc-094","stem":"Which suffix identifies angiotensin-converting enzyme (ACE) inhibitors?","options":["-sartan","-olol","-pril","-dipine"],"correctIndex":2,"rationale":"ACE inhibitors end in -pril (ramipril, enalapril, lisinopril, perindopril). Ramipril (Altace) is particularly commonly prescribed in Canadian practice. ARBs end in -sartan, beta-blockers in -olol, CCBs in -dipine.","difficulty":1,"category":"Drug Classifications","topic":"drug suffixes","certification":"PEBC"},
  {"id":"pebc-095","stem":"A Canadian pharmacy technician performs a product check on a colleague's dispensing. The label shows 'Ramipril 5 mg' but the bottle used was Ramipril 10 mg. What should happen?","options":["Dispense as is since ramipril is ramipril","Stop the dispensing, correct the error, and document it","Contact the prescriber to change the strength","Tell the patient to take half a tablet"],"correctIndex":1,"rationale":"This is a wrong-strength error. The technician must stop the process, correct the error by redispensing with the correct strength, and document the near-miss for quality improvement. Tech-check-tech catches these errors before they reach the patient.","difficulty":1,"category":"Medication Safety","topic":"dispensing error prevention","certification":"PEBC"},
  {"id":"pebc-096","stem":"What is the typical shelf life assignment for a compounded non-aqueous preparation when no stability data is available, per Canadian compounding guidelines?","options":["7 days","14 days","90 days","180 days"],"correctIndex":2,"rationale":"Per USP <795> (also adopted in Canadian practice), non-aqueous liquid and semisolid compounded preparations without stability data should be assigned a BUD of 90 days (or the earliest expiration of any component, whichever is shorter). Aqueous preparations get 14 days refrigerated.","difficulty":2,"category":"Compounding","topic":"beyond-use dating","certification":"PEBC"},
  {"id":"pebc-097","stem":"In Canada, what is the role of the Canadian Agency for Drugs and Technologies in Health (CADTH)?","options":["Manufactures generic drugs","Provides evidence-based recommendations on drug reimbursement","Regulates pharmacy practice","Issues DINs for new drugs"],"correctIndex":1,"rationale":"CADTH provides evidence-based recommendations on the clinical and cost-effectiveness of drugs and health technologies. Its Common Drug Review (CDR) process informs provincial drug plan formulary decisions across Canada (except Quebec, which has its own process through INESSS).","difficulty":3,"category":"Regulations/Law","topic":"CADTH","certification":"PEBC"},
  {"id":"pebc-098","stem":"How many mL of water should be added to 50 mL of 100% ethanol to make a 70% ethanol solution?","options":["15 mL","21.4 mL","30 mL","50 mL"],"correctIndex":1,"rationale":"Using C1V1 = C2V2: 100% × 50 mL = 70% × V2. V2 = 5000/70 = 71.4 mL total volume. Water to add: 71.4 - 50 = 21.4 mL. This dilution is used in Canadian pharmacy compounding for antiseptic preparation.","difficulty":3,"category":"Dosage Calculations","topic":"dilution calculations","certification":"PEBC"},
  {"id":"pebc-099","stem":"A prescription for a narcotic in Canada must be retained by the pharmacy for a minimum of:","options":["6 months","1 year","2 years","5 years"],"correctIndex":2,"rationale":"The CDSA Narcotic Control Regulations require pharmacies to retain narcotic prescriptions for a minimum of 2 years. Some provinces require longer retention (e.g., 10 years in some provinces). Records must be available for Health Canada inspection.","difficulty":2,"category":"Regulations/Law","topic":"record retention","certification":"PEBC"},
  {"id":"pebc-100","stem":"Which of the following is an example of a 'high-alert medication' identified by ISMP Canada?","options":["Acetaminophen 500 mg tablets","Insulin aspart (NovoRapid)","Cetirizine 10 mg tablets","Ranitidine 150 mg tablets"],"correctIndex":1,"rationale":"Insulin (all types including NovoRapid/insulin aspart) is classified as a high-alert medication by ISMP Canada. These drugs bear a heightened risk of causing significant patient harm when used in error. Other high-alert medications include opioids, anticoagulants, and concentrated electrolytes.","difficulty":1,"category":"Medication Safety","topic":"high-alert medications","certification":"PEBC"},
  {"id":"pebc-101","stem":"What is the Canadian generic prefix 'pms-' an abbreviation for?","options":["Pharmaceutical Standards","Pharmascience","Pharmacare Medical Supply","Primary Medical Solutions"],"correctIndex":1,"rationale":"The 'pms-' prefix identifies generic products manufactured by Pharmascience Inc., a major Canadian generic pharmaceutical company based in Montreal. Other Canadian generic prefixes include 'Apo-' (Apotex), 'Teva-' (Teva Canada), and 'Sandoz' (Sandoz Canada).","difficulty":1,"category":"Pharmacology","topic":"Canadian generic manufacturers","certification":"PEBC"},
  {"id":"pebc-102","stem":"A prescription reads: 'Ramipril 10 mg PO daily, #90, Refills x 3.' How many total tablets will the patient receive over the entire prescription?","options":["90 tablets","180 tablets","270 tablets","360 tablets"],"correctIndex":3,"rationale":"Original fill: 90 tablets + 3 refills × 90 tablets = 90 + 270 = 360 total tablets. This is a common calculation for insurance billing and supply management in Canadian pharmacy practice.","difficulty":1,"category":"Dosage Calculations","topic":"total supply calculations","certification":"PEBC"},
  {"id":"pebc-103","stem":"In Canadian hospital pharmacy, what is an 'Automatic Stop Order'?","options":["An order that automatically refills medications","An institutional policy that discontinues certain medications after a predetermined time unless renewed","An order to stop dispensing controlled substances","A system for automatically reordering stock"],"correctIndex":1,"rationale":"Automatic stop orders are institutional policies that discontinue certain medications (especially antibiotics, anticoagulants, and opioids) after a set period unless the prescriber renews the order. This prevents unnecessary prolonged therapy and is common in Canadian hospitals.","difficulty":2,"category":"Prescription Processing","topic":"hospital order management","certification":"PEBC"},
  {"id":"pebc-104","stem":"Which vitamin/mineral supplement interaction is important to counsel patients about when dispensing levothyroxine?","options":["Vitamin C decreases absorption","Calcium and iron supplements decrease absorption — take 4 hours apart","Vitamin B12 increases toxicity","Magnesium increases absorption"],"correctIndex":1,"rationale":"Calcium, iron, aluminum-containing antacids, and soy products significantly decrease levothyroxine absorption. Patients should take levothyroxine on an empty stomach and wait at least 4 hours before taking calcium or iron supplements. This counseling point applies in both Canadian and US practice.","difficulty":2,"category":"Drug Interactions","topic":"supplement-drug interactions","certification":"PEBC"},
  {"id":"pebc-105","stem":"What does the Canadian abbreviation 'NIHB' stand for in pharmacy billing?","options":["National Institutional Health Board","Non-Insured Health Benefits (federal program for Indigenous peoples)","National Insurance Health Bureau","Northern Island Health Benefits"],"correctIndex":1,"rationale":"NIHB (Non-Insured Health Benefits) is a federal program that provides drug coverage for eligible First Nations and Inuit peoples in Canada. Pharmacy technicians must know how to bill NIHB as a third-party payer when processing prescriptions for eligible patients.","difficulty":2,"category":"Prescription Processing","topic":"federal drug coverage","certification":"PEBC"},
  {"id":"pebc-106","stem":"A sterile compounding pharmacy in Canada must follow which standard?","options":["USP <795> only","USP <797> and applicable provincial standards","CDSA regulations only","No specific standards apply"],"correctIndex":1,"rationale":"Canadian sterile compounding pharmacies follow USP <797> standards (adopted by reference in most provincial regulations) along with any additional provincial requirements. This includes cleanroom classifications, garbing procedures, BUD assignment, and quality assurance testing.","difficulty":2,"category":"Sterile Products","topic":"sterile compounding standards","certification":"PEBC"},
  {"id":"pebc-107","stem":"What is the concentration of D10W?","options":["1% dextrose in water","5% dextrose in water","10% dextrose in water","50% dextrose in water"],"correctIndex":2,"rationale":"D10W means 10% dextrose in water — 10 g of dextrose per 100 mL. D5W is 5% dextrose, D50W is 50% dextrose. These are standard IV solutions used in Canadian hospitals for hydration and glucose supplementation.","difficulty":1,"category":"Dosage Calculations","topic":"IV solution concentrations","certification":"PEBC"},
  {"id":"pebc-108","stem":"In Canada, a pharmacy technician discovers that a controlled substance count is short by 2 tablets. After notifying the pharmacist, what documentation is required?","options":["No documentation needed if the amount is small","A written record of the discrepancy including date, drug, quantity, investigation findings, and signatures","Only a verbal report to the pharmacy manager","An email to Health Canada"],"correctIndex":1,"rationale":"All controlled substance discrepancies must be documented in writing, including the date, drug name and strength, quantity discrepant, investigation findings, corrective actions, and signatures of involved personnel. If theft is suspected, Health Canada and police must be notified per CDSA requirements.","difficulty":2,"category":"Medication Safety","topic":"controlled substance accountability","certification":"PEBC"},
  {"id":"pebc-109","stem":"Which Canadian brand name is used for omeprazole?","options":["Prilosec","Losec","Nexium","Prevacid"],"correctIndex":1,"rationale":"Losec is the Canadian brand name for omeprazole (AstraZeneca). In the US, it is sold as Prilosec. This is one of the most commonly cited examples of different brand names for the same drug between Canada and the US.","difficulty":1,"category":"Pharmacology","topic":"Canadian brand names","certification":"PEBC"},
  {"id":"pebc-110","stem":"A prescription calls for hydrocortisone 1% cream, dispense 60 g. How many milligrams of hydrocortisone are in the tube?","options":["6 mg","60 mg","600 mg","6000 mg"],"correctIndex":2,"rationale":"1% = 1 g per 100 g. For 60 g: (1/100) × 60 = 0.6 g = 600 mg of hydrocortisone. This percentage calculation is fundamental to Canadian pharmacy practice for both dispensing and compounding.","difficulty":1,"category":"Dosage Calculations","topic":"percentage calculations","certification":"PEBC"},
  {"id":"pebc-111","stem":"What is the Canadian equivalent of the US 'Orange Book' for therapeutic equivalence determinations?","options":["CPS (Compendium of Pharmaceuticals and Specialties)","Health Canada Therapeutic Substitution Database","Provincial Interchangeability Formularies","Canadian Drug Expert Committee rulings"],"correctIndex":2,"rationale":"Provincial Interchangeability Formularies (e.g., Ontario's Interchangeable Drug Products Formulary) list generic products deemed therapeutically equivalent and interchangeable with brand products. Health Canada's comparative bioavailability studies support these determinations.","difficulty":3,"category":"Prescription Processing","topic":"therapeutic equivalence Canada","certification":"PEBC"},
  {"id":"pebc-112","stem":"A patient in Canada needs naloxone for opioid overdose emergency. How is naloxone typically available?","options":["Prescription only","Behind-the-counter at pharmacies (NAPRA Schedule II in most provinces)","Only through hospitals","Only through addiction treatment centers"],"correctIndex":1,"rationale":"In most Canadian provinces, naloxone (Narcan nasal spray or injectable kits) is available without a prescription at pharmacies. It was rescheduled to improve accessibility as part of Canada's response to the opioid crisis. Many provinces provide it free through Take Home Naloxone programs.","difficulty":1,"category":"Pharmacology","topic":"naloxone access Canada","certification":"PEBC"},
  {"id":"pebc-113","stem":"What is the flow rate in mL/hr for 1 L of Lactated Ringer's solution to infuse over 12 hours?","options":["42 mL/hr","63 mL/hr","83 mL/hr","100 mL/hr"],"correctIndex":2,"rationale":"Flow rate = 1000 mL ÷ 12 hr = 83.3 ≈ 83 mL/hr. Lactated Ringer's solution is an isotonic crystalloid used for fluid resuscitation and rehydration in Canadian hospitals.","difficulty":1,"category":"Dosage Calculations","topic":"IV flow rates","certification":"PEBC"},
  {"id":"pebc-114","stem":"Which organization develops continuing education requirements for Canadian pharmacy technicians?","options":["Health Canada","Provincial regulatory colleges (e.g., OCP, CPBC)","NAPRA","Canadian Pharmacists Association"],"correctIndex":1,"rationale":"Provincial regulatory colleges set and enforce continuing education (CE) and continuing professional development (CPD) requirements for pharmacy technicians. Requirements vary by province but typically include a specified number of CE credits per registration period.","difficulty":1,"category":"Regulations/Law","topic":"continuing education Canada","certification":"PEBC"},
  {"id":"pebc-115","stem":"A patient's prescription for oxycodone in Canada requires a triplicate prescription form in which provinces?","options":["No provinces require triplicates anymore","British Columbia","All provinces","Only Quebec"],"correctIndex":1,"rationale":"British Columbia still uses triplicate prescription program (TPP) forms for certain controlled substances including opioids. Other provinces have moved to electronic monitoring systems (e.g., Narcotics Monitoring System in Ontario). Requirements vary by province.","difficulty":3,"category":"Regulations/Law","topic":"triplicate prescriptions","certification":"PEBC"},
  {"id":"pebc-116","stem":"What is the correct formula for calculating drip rate in gtt/min?","options":["Volume (mL) × Time (min) ÷ Drop factor","Volume (mL) × Drop factor (gtt/mL) ÷ Time (min)","Drop factor ÷ Volume × Time","Time (hr) × Drop factor ÷ Volume"],"correctIndex":1,"rationale":"Drip rate (gtt/min) = [Volume (mL) × Drop factor (gtt/mL)] ÷ Time (min). This formula is used universally in Canadian and US pharmacy for manual IV rate calculations when electronic pumps are not available.","difficulty":2,"category":"Dosage Calculations","topic":"drip rate formula","certification":"PEBC"},
  {"id":"pebc-117","stem":"In Canada, what is the maximum penalty for trafficking a CDSA Schedule I substance (e.g., heroin, cocaine)?","options":["A fine only","Up to 7 years imprisonment","Up to 14 years imprisonment","Life imprisonment"],"correctIndex":3,"rationale":"Trafficking in CDSA Schedule I substances (heroin, cocaine, fentanyl, methamphetamine) carries a maximum penalty of life imprisonment in Canada. Schedule II (cannabis) trafficking has lower maximum penalties. These serious penalties reflect the danger of these substances.","difficulty":3,"category":"Regulations/Law","topic":"CDSA penalties","certification":"PEBC"},
  {"id":"pebc-118","stem":"A patient on warfarin in Canada should maintain consistent intake of which vitamin?","options":["Vitamin C","Vitamin D","Vitamin K","Vitamin B12"],"correctIndex":2,"rationale":"Patients on warfarin should maintain consistent (not necessarily low) vitamin K intake. Vitamin K is a cofactor for clotting factors II, VII, IX, and X. Sudden increases in vitamin K (green leafy vegetables) can decrease warfarin effectiveness; sudden decreases can increase bleeding risk.","difficulty":1,"category":"Drug Interactions","topic":"warfarin-vitamin K","certification":"PEBC"},
  {"id":"pebc-119","stem":"What is the brand name for the combination product perindopril/indapamide, commonly used for hypertension in Canada?","options":["Coversyl Plus","Atacand Plus","Hyzaar","Vaseretic"],"correctIndex":0,"rationale":"Coversyl Plus (perindopril/indapamide) is a commonly prescribed Canadian combination antihypertensive. Perindopril is an ACE inhibitor, indapamide is a thiazide-like diuretic. Atacand Plus is candesartan/HCTZ, Hyzaar is losartan/HCTZ.","difficulty":2,"category":"Pharmacology","topic":"Canadian combination products","certification":"PEBC"},
  {"id":"pebc-120","stem":"If a pharmacy compounds 250 mL of a solution and 5 mL contains 100 mg of drug, what is the percentage concentration?","options":["0.2%","2%","5%","20%"],"correctIndex":1,"rationale":"100 mg/5 mL = 20 mg/mL = 2 g/100 mL = 2% (w/v). This concentration calculation confirms the strength of the compounded preparation. Quality checks should verify this against the intended concentration.","difficulty":2,"category":"Dosage Calculations","topic":"concentration verification","certification":"PEBC"},
  {"id":"pebc-121","stem":"What does the abbreviation 'prn' mean in both Canadian and US pharmacy practice?","options":["Per registered nurse","Pro re nata (as needed)","Primary route necessary","Prescription renewal notice"],"correctIndex":1,"rationale":"PRN means 'pro re nata' (as needed/as the situation demands). It is used identically in Canadian and US pharmacy practice. A PRN medication is taken only when the patient needs it, rather than on a fixed schedule.","difficulty":1,"category":"Prescription Processing","topic":"sig codes","certification":"PEBC"},
  {"id":"pebc-122","stem":"A Canadian pharmacy receives a notification about a Class II Health Canada recall. What does Class II indicate?","options":["Imminent danger of death","Temporary or medically reversible adverse effects, or low probability of serious consequences","Minor violation unlikely to cause adverse health effects","Voluntary recall, no health risk"],"correctIndex":1,"rationale":"Health Canada Class II recalls involve products that may cause temporary or medically reversible adverse health consequences, or where the probability of serious consequences is low. Class I is most serious (death/serious harm), Class III is least serious (unlikely to cause harm).","difficulty":2,"category":"Inventory Management","topic":"Health Canada recalls","certification":"PEBC"},
  {"id":"pebc-123","stem":"A dose of morphine 10 mg IM is ordered. The vial contains 15 mg/mL. What volume should be drawn?","options":["0.33 mL","0.5 mL","0.67 mL","1 mL"],"correctIndex":2,"rationale":"Volume = Dose ÷ Concentration = 10 mg ÷ 15 mg/mL = 0.667 ≈ 0.67 mL. Morphine is a CDSA narcotic; all calculations must be independently verified before administration in Canadian healthcare settings.","difficulty":2,"category":"Dosage Calculations","topic":"narcotic dose calculations","certification":"PEBC"},
  {"id":"pebc-124","stem":"In Canada, what is the primary difference between a 'pharmacist' and a 'pharmacy technician' in terms of patient care?","options":["There is no difference","The pharmacist performs clinical assessment and patient counseling; the technician performs technical dispensing functions","The technician supervises the pharmacist","Both can counsel patients independently"],"correctIndex":1,"rationale":"In Canadian pharmacy, the pharmacist is responsible for clinical assessment, therapeutic decision-making, drug interaction review, and patient counseling. The pharmacy technician performs technical functions including prescription processing, product preparation, and inventory management within defined scope of practice.","difficulty":1,"category":"Regulations/Law","topic":"roles and responsibilities","certification":"PEBC"},
  {"id":"pebc-125","stem":"How many grams of sodium chloride are in 500 mL of 3% hypertonic saline?","options":["1.5 g","4.5 g","15 g","30 g"],"correctIndex":2,"rationale":"3% = 3 g/100 mL. For 500 mL: 3 × (500/100) = 15 g of NaCl. Hypertonic saline (3%) is a high-alert medication used for severe hyponatremia in Canadian hospitals and requires careful monitoring.","difficulty":2,"category":"Dosage Calculations","topic":"IV solution calculations","certification":"PEBC"},
  {"id":"pebc-126","stem":"What is 'medication reconciliation' in Canadian healthcare?","options":["Returning unused medications to the pharmacy","A formal process of comparing a patient's medication orders to all medications they are actually taking to identify discrepancies","Billing reconciliation for insurance claims","Counting controlled substances"],"correctIndex":1,"rationale":"Medication reconciliation (MedRec) is a formal process required by Accreditation Canada at transitions of care (admission, transfer, discharge). It identifies and resolves discrepancies between the patient's actual medication list and current orders to prevent errors.","difficulty":1,"category":"Medication Safety","topic":"medication reconciliation","certification":"PEBC"},
  {"id":"pebc-127","stem":"Which Canadian regulation specifically addresses the handling of hazardous drugs in pharmacy?","options":["WHMIS 2015","USP <800> (adopted by provincial standards)","Canada Labour Code Part II","Both A and B"],"correctIndex":3,"rationale":"In Canadian pharmacies, hazardous drug handling is governed by both WHMIS 2015 (Workplace Hazardous Materials Information System, for SDS and labeling) and USP <800> (adopted by most provincial pharmacy regulatory standards for handling procedures, PPE, and engineering controls).","difficulty":3,"category":"Sterile Products","topic":"hazardous drug handling Canada","certification":"PEBC"},
  {"id":"pebc-128","stem":"A prescription reads 'Apo-Metformin 500 mg PO BID with meals.' What does 'with meals' indicate?","options":["Take on an empty stomach","Take with food to reduce GI side effects","Take 30 minutes before eating","Take at bedtime"],"correctIndex":1,"rationale":"Metformin should be taken with meals to reduce common gastrointestinal side effects (nausea, diarrhea, abdominal discomfort). This administration instruction is important for patient adherence. 'Apo-Metformin' is a Canadian generic (Apotex).","difficulty":1,"category":"Pharmacology","topic":"administration instructions","certification":"PEBC"},
  {"id":"pebc-129","stem":"What is the appropriate action if a patient in Canada presents a prescription that appears to have been altered?","options":["Fill the prescription as presented","Notify the pharmacist immediately for assessment","Contact the police directly","Refuse service and ask the patient to leave"],"correctIndex":1,"rationale":"If a prescription appears altered (changed quantity, strength, or drug), the pharmacy technician should immediately notify the pharmacist. The pharmacist will verify with the prescriber. Suspected forgery or alteration of controlled substance prescriptions may need to be reported to authorities.","difficulty":1,"category":"Medication Safety","topic":"prescription fraud prevention","certification":"PEBC"},
  {"id":"pebc-130","stem":"What is the shelf life of a properly stored, unopened insulin pen in Canada?","options":["7 days","28 days","Until the manufacturer's expiration date","6 months from dispensing"],"correctIndex":2,"rationale":"Unopened insulin pens stored at 2-8°C are good until the manufacturer's expiration date. Once opened or in-use, most insulin pens are good for 28-42 days at room temperature (varies by product). Patients should check the specific product monograph for their insulin type.","difficulty":1,"category":"Inventory Management","topic":"insulin storage","certification":"PEBC"}
];
